AND( NOT( ISPICKVAL(Status__c, 'Resubmitted') ), NOT( ISPICKVAL(Status__c, 'Pending Client') ), NOT( ISPICKVAL(Status__c, 'Cancelled') ), NOT( ISPICKVAL(Status__c, 'Completed')), ISPICKVAL(Request_Type__c, 'NDA'), RecordType.DeveloperName = 'Legal_Services' , OR( $Profile.Name = 'SW CSM Internal', $Profile.Name = 'SW Sales Internal', $Profile.Name = 'SW Sales Internal - STRAT', $Profile.Name = 'SW Sales External', $Profile.Name = 'SW Management' ), $Profile.Name <> 'SW Billing', $Profile.Name <> 'SW Billing Extended', $Profile.Name <> 'System Administrator', $Profile.Name <> 'SW SalesOps', $Profile.Name <> 'SW SalesOps Extended', $Profile.Name <> 'SW Legal', $User.Id <> '005b0000000lqbnAAA' /*Automated Process*/, $User.Id <> '005b0000000lqbn' /*Automated Process*/ )
